function solve(m: number, n: number, waitCost: number[][]): number {
    const dist = Array(m).fill(0).map(() => Array(n).fill(0).map(() => [Infinity, Infinity]));
    dist[0][0][1] = 1;
    const queue: [number, number, number, number][] = [[1, 0, 0, 1]];
    const directions = [[0, 1], [1, 0]];

    while (queue.length > 0) {
        queue.sort((a, b) => a[0] - b[0]);
        const [cost, i, j, parity] = queue.shift()!;

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (cost > dist[i][j][parity]) {
            continue;
        }

        if (parity === 1) {
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const newCost = cost + (ni + 1) * (nj + 1);
                    const new_parity = 0;
                    if (newCost < dist[ni][nj][new_parity]) {
                        dist[ni][nj][new_parity] = newCost;
                        queue.push([newCost, ni, nj, new_parity]);
                    }
                }
            }
        } else {
            const newCost = cost + waitCost[i][j];
            const new_parity = 1;
            if (newCost < dist[i][j][new_parity]) {
                dist[i][j][new_parity] = newCost;
                queue.push([newCost, i, j, new_parity]);
            }
        }
    }

    return -1;
}
